import{_ as e,o as l,c as i,ao as a}from"./chunks/framework.BtTNxi1d.js";const y=JSON.parse('{"title":"Benchmarks","description":"","frontmatter":{},"headers":[],"relativePath":"benchmarks.md","filePath":"benchmarks.md","lastUpdated":null}'),d={name:"benchmarks.md"};function r(g,t,s,n,h,o){return l(),i("div",null,[...t[0]||(t[0]=[a('<h1 id="Benchmarks" tabindex="-1">Benchmarks <a class="header-anchor" href="#Benchmarks" aria-label="Permalink to &quot;Benchmarks {#Benchmarks}&quot;">​</a></h1><p>The benchmark grid from the parallel <code>gllvmTMB-julia-bench/</code> study compares R <code>gllvmTMB</code> and GLLVM.jl on the same simulated data per replicate. Both engines minimise the same Gaussian marginal log-likelihood with <code>f_reltol = 1e-10</code> and <code>g_tol = 1e-6</code>. The R engine uses <code>gllvmTMB::gllvmTMB</code> (TMB Laplace + L-BFGS); the Julia engine uses <code>GLLVM.fit_gaussian_gllvm</code> (closed-form Gaussian marginal + <code>Optim</code> L-BFGS with <code>ForwardDiff</code> gradients).</p><p>Six cells × three replicates × two engines = 36 fits. All 36 converged.</p><h2 id="Wall-clock-median-over-reps" tabindex="-1">Wall-clock (median over reps) <a class="header-anchor" href="#Wall-clock-median-over-reps" aria-label="Permalink to &quot;Wall-clock (median over reps) {#Wall-clock-median-over-reps}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">cell_id</th><th style="text-align:right;">n_sites</th><th style="text-align:right;">n_species</th><th style="text-align:right;">d</th><th style="text-align:right;">median t_R (s)</th><th style="text-align:right;">median t_Julia (s)</th><th style="text-align:right;">median R / Julia</th></tr></thead><tbody><tr><td style="text-align:right;">c01_small_noX</td><td style="text-align:right;">20</td><td style="text-align:right;">5</td><td style="text-align:right;">1</td><td style="text-align:right;">0.0230</td><td style="text-align:right;">0.0001</td><td style="text-align:right;">194.9</td></tr><tr><td style="text-align:right;">c02_small_X</td><td style="text-align:right;">20</td><td style="text-align:right;">5</td><td style="text-align:right;">1</td><td style="text-align:right;">0.0250</td><td style="text-align:right;">0.0001</td><td style="text-align:right;">185.3</td></tr><tr><td style="text-align:right;">c03_med_noX</td><td style="text-align:right;">80</td><td style="text-align:right;">10</td><td style="text-align:right;">2</td><td style="text-align:right;">0.1020</td><td style="text-align:right;">0.0002</td><td style="text-align:right;">698.1</td></tr><tr><td style="text-align:right;">c04_med_X</td><td style="text-align:right;">80</td><td style="text-align:right;">10</td><td style="text-align:right;">2</td><td style="text-align:right;">0.1120</td><td style="text-align:right;">0.0003</td><td style="text-align:right;">335.3</td></tr><tr><td style="text-align:right;">c05_large_noX</td><td style="text-align:right;">200</td><td style="text-align:right;">20</td><td style="text-align:right;">2</td><td style="text-align:right;">0.5140</td><td style="text-align:right;">0.0013</td><td style="text-align:right;">398.8</td></tr><tr><td style="text-align:right;">c06_large_X</td><td style="text-align:right;">200</td><td style="text-align:right;">20</td><td style="text-align:right;">2</td><td style="text-align:right;">0.6180</td><td style="text-align:right;">0.0037</td><td style="text-align:right;">161.2</td></tr></tbody></table><p>Julia is the faster engine in every cell after a per-signature warm-up. The relative speedup is largest in the smallest cells (where the R-side TMB Laplace setup dominates a small inner loop) and the absolute time saved per fit is largest in the larger cells — the metric that matters for a multi-thousand-fit simulation study.</p><h2 id="Agreement-worst-case-across-the-grid" tabindex="-1">Agreement (worst-case across the grid) <a class="header-anchor" href="#Agreement-worst-case-across-the-grid" aria-label="Permalink to &quot;Agreement (worst-case across the grid) {#Agreement-worst-case-across-the-grid}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">cell_id</th><th style="text-align:right;">max |Δ logLik|</th><th style="text-align:right;">max Σ_y rel-Frobenius</th></tr></thead><tbody><tr><td style="text-align:right;">c01_small_noX</td><td style="text-align:right;">4.965e-10</td><td style="text-align:right;">5.769e-06</td></tr><tr><td style="text-align:right;">c02_small_X</td><td style="text-align:right;">4.443e-10</td><td style="text-align:right;">5.519e-06</td></tr><tr><td style="text-align:right;">c03_med_noX</td><td style="text-align:right;">3.683e-08</td><td style="text-align:right;">1.804e-05</td></tr><tr><td style="text-align:right;">c04_med_X</td><td style="text-align:right;">3.839e-08</td><td style="text-align:right;">2.810e-05</td></tr><tr><td style="text-align:right;">c05_large_noX</td><td style="text-align:right;">1.923e-07</td><td style="text-align:right;">3.742e-05</td></tr><tr><td style="text-align:right;">c06_large_X</td><td style="text-align:right;">2.343e-07</td><td style="text-align:right;">4.424e-05</td></tr></tbody></table><p>Worst-case <code>|Δ logLik|</code> over the full grid is <strong>2.343e-07</strong> (gate <code>&lt; 1e-4</code>: PASS). Worst-case relative Frobenius on <code>Σ_y</code> is <strong>4.424e-05</strong> (gate <code>&lt; 1e-3</code>: PASS). The two engines agree to at least six significant digits on every fit.</p><p>Full per-rep details, the wall-clock log-log plot, and the verification gate summary live in the source benchmark repo at <code>gllvmTMB-julia-bench/report/grid-bench.md</code>.</p><h2 id="Op-phylogenetic-gradient-scaling" tabindex="-1">O(p) phylogenetic gradient scaling <a class="header-anchor" href="#Op-phylogenetic-gradient-scaling" aria-label="Permalink to &quot;O(p) phylogenetic gradient scaling {#Op-phylogenetic-gradient-scaling}&quot;">​</a></h2><p>The headline of the node-frame analytic gradient (<code>grad_node_perspecies</code>) is that a single <strong>exact</strong> gradient evaluation scales <strong>linearly</strong> in the number of species <code>p</code> on a tree — where R <code>gllvmTMB</code> caps near <code>p ≈ 500</code>. Timed on a balanced tree (one evaluation, median over <code>BenchmarkTools</code> samples; reproduce with <code>julia --project=bench bench/node_gradient_bench.jl</code>):</p><table tabindex="0"><thead><tr><th style="text-align:right;">p</th><th style="text-align:right;">state build (ms)</th><th style="text-align:right;">gradient (ms)</th><th style="text-align:right;">gradient / p (µs)</th></tr></thead><tbody><tr><td style="text-align:right;">100</td><td style="text-align:right;">0.088</td><td style="text-align:right;">0.0094</td><td style="text-align:right;">0.094</td></tr><tr><td style="text-align:right;">500</td><td style="text-align:right;">0.287</td><td style="text-align:right;">0.041</td><td style="text-align:right;">0.081</td></tr><tr><td style="text-align:right;">1 000</td><td style="text-align:right;">0.583</td><td style="text-align:right;">0.077</td><td style="text-align:right;">0.077</td></tr><tr><td style="text-align:right;">5 000</td><td style="text-align:right;">2.935</td><td style="text-align:right;">0.393</td><td style="text-align:right;">0.079</td></tr><tr><td style="text-align:right;">10 000</td><td style="text-align:right;">5.968</td><td style="text-align:right;">0.771</td><td style="text-align:right;">0.077</td></tr></tbody></table><p>The per-tip time (last column) is essentially flat, and the log–log scaling slope is <strong>0.96 for the gradient</strong> and <strong>0.92 for the state build</strong> — both ≈ 1, confirming <code>O(p)</code>. A single exact gradient at <code>p = 10 000</code> takes <strong>0.77 ms</strong>. (The older <code>sparse_phy_grad</code> path is <code>O(p²)</code>, slope ≈ 2; it is retained as an independent-complexity cross-check, not the production path.)</p>',14)])])}const x=e(d,[["render",r]]);export{y as __pageData,x as default};
